import numpy as np

class PolynomialRegression:
    def __init__(self, degree: int = 2):
        self.degree = degree
        self.w = None

    def expand_features(self, X: np.ndarray) -> np.ndarray:
        x = X.ravel()  # (N,)
        # Columns: x^1, x^2, ..., x^degree
        return np.stack([x ** d for d in range(1, self.degree + 1)], axis=1)  # (N, degree)

    def fit(self, X: np.ndarray, y: np.ndarray) -> None:
        X_poly = self.expand_features(X)       # (N, degree)
        N = X_poly.shape[0]
        # Add bias column
        X_b = np.hstack([X_poly, np.ones((N, 1))])  # (N, degree+1)
        self.w, _, _, _ = np.linalg.lstsq(X_b, y, rcond=None)

    def predict(self, X: np.ndarray) -> np.ndarray:
        X_poly = self.expand_features(X)
        N = X_poly.shape[0]
        X_b = np.hstack([X_poly, np.ones((N, 1))])
        return X_b @ self.w
